import { Sliders, Brain, Sparkles, Calculator } from 'lucide-react';

const DualLLMBrain = () => {
  // Stage 1: Hardcoded example
  const [targetAlpha, setTargetAlpha] = useState(0.7); // 0 = all B, 1 = all A
  const [selectedDomain, setSelectedDomain] = useState('creative');
  const [useDP, setUseDP] = useState(false); // Toggle between Greedy and DP

  // Domain presets (Ben Franklin style)
  const domains = {
    creative: { name: 'Creative Writing', alpha: 0.85, color: 'orange', icon: Sparkles },
    balanced: { name: 'Product Design', alpha: 0.60, color: 'purple', icon: Brain },
    analytical: { name: 'Code Debugging', alpha: 0.25, color: 'blue', icon: Calculator }
  };

  // Example tokens with VARIABLE COSTS (computational weight)
  // Simple words = cheap, complex thoughts = expensive
  const tokenData = [
    { text: "In", cost: 1, sentence: 0 },
    { text: "a", cost: 1, sentence: 0 },
    { text: "world", cost: 2, sentence: 0 },
    { text: "where", cost: 1, sentence: 0 },
    { text: "AI consciousness", cost: 5, sentence: 0 }, // Heavy concept
    { text: "emerged,", cost: 3, sentence: 0 },
    { text: "the", cost: 1, sentence: 1 },
    { text: "first", cost: 1, sentence: 1 },
    { text: "question", cost: 2, sentence: 1 },
    { text: "wasn't", cost: 1, sentence: 1 },
    { text: "ethics", cost: 3, sentence: 1 },
    { text: "but", cost: 1, sentence: 1 },
    { text: "identity.", cost: 4, sentence: 1 }, // Heavy concept
    { text: "Who", cost: 1, sentence: 2 },
    { text: "am I", cost: 3, sentence: 2 },
    { text: "when", cost: 1, sentence: 2 },
    { text: "I", cost: 1, sentence: 2 },
    { text: "exist?", cost: 2, sentence: 2 }
  ];

  const tokens = tokenData.map(t => t.text);
  const costs = tokenData.map(t => t.cost);
  const sentences = tokenData.map(t => t.sentence);

  // Group tokens into sentences for atomic assignment
  const sentenceGroups = useMemo(() => {
    const groups = [];
    let current = { tokens: [], costs: [], totalCost: 0, sentenceId: sentences[0], startIdx: 0 };

    for (let i = 0; i < tokens.length; i++) {
      if (i > 0 && sentences[i] !== sentences[i-1]) {
        groups.push(current);
        current = { tokens: [], costs: [], totalCost: 0, sentenceId: sentences[i], startIdx: i };
      }
      current.tokens.push(tokens[i]);
      current.costs.push(costs[i]);
      current.totalCost += costs[i];
    }
    groups.push(current);
    return groups;
  }, [tokens, costs, sentences]);

  // Dynamic Programming solution (globally optimal)
  const dpSolution = useMemo(() => {
    const numSentences = sentenceGroups.length;
    const totalCost = costs.reduce((sum, c) => sum + c, 0);
    const targetCostA = totalCost * targetAlpha;
    const switchCostRate = 0.05;

    // DP table: M[s][costA] = { totalWaste, lastAssignment, prevCostA }
    const M = Array(numSentences + 1).fill(null).map(() => 
      Array(totalCost + 1).fill(null).map(() => ({ 
        waste: Infinity, 
        lastAssignment: null,
        prevCostA: null 
      }))
    );

    M[0][0] = { waste: 0, lastAssignment: null, prevCostA: null };

    // Fill DP table
    for (let s = 1; s <= numSentences; s++) {
      const sentenceCost = sentenceGroups[s-1].totalCost;

      for (let costA = 0; costA <= totalCost; costA++) {
        // Option 1: Assign sentence to LLM A
        if (costA >= sentenceCost) {
          const prevCostA = costA - sentenceCost;
          if (M[s-1][prevCostA].waste !== Infinity) {
            const switchPenalty = M[s-1][prevCostA].lastAssignment === 'B' 
              ? switchCostRate * totalCost : 0;
            const currentRatio = costA / totalCost;
            const deviationPenalty = Math.abs(currentRatio - targetAlpha) * totalCost;
            const totalWaste = M[s-1][prevCostA].waste + switchPenalty + deviationPenalty;

            if (totalWaste < M[s][costA].waste) {
              M[s][costA] = { 
                waste: totalWaste, 
                lastAssignment: 'A',
                prevCostA: prevCostA
              };
            }
          }
        }

        // Option 2: Assign sentence to LLM B (costA stays same)
        if (M[s-1][costA].waste !== Infinity) {
          const switchPenalty = M[s-1][costA].lastAssignment === 'A' 
            ? switchCostRate * totalCost : 0;
          const currentRatio = costA / totalCost;
          const deviationPenalty = Math.abs(currentRatio - targetAlpha) * totalCost;
          const totalWaste = M[s-1][costA].waste + switchPenalty + deviationPenalty;

          if (totalWaste < M[s][costA].waste) {
            M[s][costA] = { 
              waste: totalWaste, 
              lastAssignment: 'B',
              prevCostA: costA
            };
          }
        }
      }
    }

    // Find best final state (minimize total waste)
    let bestCostA = 0;
    let bestWaste = Infinity;
    for (let costA = 0; costA <= totalCost; costA++) {
      if (M[numSentences][costA].waste < bestWaste) {
        bestWaste = M[numSentences][costA].waste;
        bestCostA = costA;
      }
    }

    // Reconstruct optimal path
    const sentenceAssignments = [];
    let currentCostA = bestCostA;
    for (let s = numSentences; s > 0; s--) {
      sentenceAssignments.unshift(M[s][currentCostA].lastAssignment);
      currentCostA = M[s][currentCostA].prevCostA;
    }

    // Expand sentence assignments to token assignments
    const tokenAssignments = [];
    sentenceAssignments.forEach((assignment, i) => {
      const sentence = sentenceGroups[i];
      sentence.tokens.forEach(() => tokenAssignments.push(assignment));
    });

    return {
      assignments: tokenAssignments,
      sentenceAssignments,
      optimalWaste: bestWaste,
      optimalCostA: bestCostA
    };
  }, [sentenceGroups, targetAlpha, costs]);

  // Choose algorithm based on toggle
  const partition = useMemo(() => {
    const n = tokens.length;
    const totalCost = costs.reduce((sum, c) => sum + c, 0);
    const targetCostA = totalCost * targetAlpha;
    const targetCostB = totalCost * (1 - targetAlpha);
    const switchCostRate = 0.05;

    let assignments, costA, costB;

    if (useDP) {
      // Use DP solution
      assignments = dpSolution.assignments;
      costA = dpSolution.optimalCostA;
      costB = totalCost - costA;
    } else {
      // Use greedy solution
      assignments = [];
      costA = 0;
      costB = 0;
      let lastAssignment = null;

      for (let i = 0; i < n; i++) {
        const tokenCost = costs[i];
        const currentSentence = sentences[i];
        const isNewSentence = i === 0 || sentences[i] !== sentences[i - 1];

        // CONSTRAINT: Can't switch mid-sentence (market regulation)
