          assignments.push(lastAssignment);
          if (lastAssignment === 'A') {
            costA += tokenCost;
          } else {
            costB += tokenCost;
          }
          continue;
        }

        // Calculate current ratios
        const totalSpent = costA + costB;
        const currentRatio = totalSpent > 0 ? costA / totalSpent : 0;

        // Market decision: which producer gets this work?
        const remainingCostA = targetCostA - costA;
        const remainingCostB = targetCostB - costB;

        // Greedy: assign to whoever is further from target
        let assignment;
        if (remainingCostA > 0 && (remainingCostB <= 0 || currentRatio < targetAlpha)) {
          assignment = 'A';
          costA += tokenCost;
        } else {
          assignment = 'B';
          costB += tokenCost;
        }

        assignments.push(assignment);
        lastAssignment = assignment;
      }
    }

    const achievedAlpha = costA / totalCost;
    const switches = assignments.filter((a, i) => i > 0 && a !== assignments[i-1]).length;

    // Economic metrics
    const efficiency = 1 - Math.abs(achievedAlpha - targetAlpha);
    const switchCost = switches * switchCostRate * totalCost;
    const imbalanceCost = Math.abs(costA - targetCostA) + Math.abs(costB - targetCostB);
    const totalWaste = switchCost + imbalanceCost;

    return {
      assignments,
      countA: assignments.filter(a => a === 'A').length,
      countB: assignments.filter(a => a === 'B').length,
      costA: Math.round(costA * 10) / 10,
      costB: Math.round(costB * 10) / 10,
      totalCost,
      achievedAlpha,
      switches,
      efficiency: efficiency * 100,
      switchCost: Math.round(switchCost * 10) / 10,
      imbalanceCost: Math.round(imbalanceCost * 10) / 10,
      totalWaste: Math.round(totalWaste * 10) / 10,
      marketEfficiency: ((totalCost - totalWaste) / totalCost) * 100,
      algorithm: useDP ? 'Dynamic Programming (Optimal)' : 'Greedy (Approximate)'
    };
  }, [tokens, targetAlpha, costs, sentences, useDP, dpSolution]);

  const deviation = Math.abs(targetAlpha - partition.achievedAlpha);

  return (
    <div className="w-full max-w-6xl mx-auto p-8 bg-gradient-to-br from-slate-900 to-slate-800 text-white rounded-xl">
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-4xl font-bold mb-2 flex items-center gap-3">
          <Brain className="w-10 h-10 text-purple-400" />
          Dual-LLM Brain Orchestrator
        </h1>
        <p className="text-slate-300">
          Visualizing System 1 (Creative) ↔ System 2 (Analytical) token partitioning
        </p>
      </div>

      {/* Domain Selection */}
      <div className="mb-6">
        <label className="block text-sm font-semibold mb-3 text-slate-300">
          Conversation Domain
        </label>
        <div className="grid grid-cols-3 gap-3">
          {Object.entries(domains).map(([key, domain]) => {
            const Icon = domain.icon;
            return (
              <button
                key={key}
